import React, { useState } from "react";
import { BrowserRouter, Routes, Route } from "react-router-dom";
import banner1 from "./components/images/banner1";
import Navbar from "./components/Navbar";
import Categories from "./components/Categories";
import Products from "./components/Products";
import Cart from "./components/Cart";
import ProductDetail from "./components/ProductDetail";
import Checkout from "./components/Checkout";
import Success from "./components/Success";

import "./App.css";

function App() {
  const [cart, setCart] = useState([]);
  const [search, setSearch] = useState("");
  const [category, setCategory] = useState("All");

  const addToCart = (item) => {
    setCart([...cart, item]);
  };

  const removeFromCart = (index) => {
    const updated = [...cart];
    updated.splice(index, 1);
    setCart(updated);
  };

  return (
    <BrowserRouter>

      <Navbar cartCount={cart.length} setSearch={setSearch} />

      <Routes>

        <Route
          path="/"
          element={
            <>
              {/* Categories */}
              {search.trim() === "" && (
                <Categories setCategory={setCategory} />
              )}

              {/* 🔥 PRODUCTS + MINI BANNER */}
              <div className="home-layout">

                {/* LEFT: PRODUCTS */}
                <div className="left-section">
                  <Products
                    addToCart={addToCart}
                    search={search}
                    category={category}
                  />
                </div>

                {/* RIGHT: MINI BANNER (same as product card) */}
                {search.trim() === "" && (
                  <div className="right-section">

                    <div className="mini-banner">
                      <img
                        src="https://images.unsplash.com/photo-1521335629791-ce4aec67dd53?w=400"
                        alt="ad"
                      />
                      <h4>Shop Fashion</h4>
                      <button>Explore</button>
                    </div>

                  </div>
                )}

              </div>
            </>
          }
        />

        <Route
          path="/product/:id"
          element={<ProductDetail addToCart={addToCart} />}
        />

        <Route
          path="/cart"
          element={<Cart cart={cart} removeFromCart={removeFromCart} />}
        />

        <Route
          path="/checkout"
          element={<Checkout cart={cart} setCart={setCart} />}
        />

        <Route path="/success" element={<Success />} />

      </Routes>

    </BrowserRouter>
  );
}

export default App;
